package com.hospital.management.controller.admission;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.BedServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admin/beds/create")public class BedCreateServlet extends HttpServlet{protected final BedService s=new BedServiceImpl();protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{q.setAttribute("bedForm",new BedForm());show(q,r,"CREATE");}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{BedForm f=form(q);ServiceResult<Long>x=s.createBed(f,AdmissionRequest.audit(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/admin/beds/view?id="+x.getData());return;}q.setAttribute("bedForm",f);q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());show(q,r,"CREATE");}protected BedForm form(HttpServletRequest q){BedForm f=new BedForm();f.setBedId(AdmissionRequest.id(q.getParameter("bedId")));f.setRoomId(AdmissionRequest.id(q.getParameter("roomId")));f.setBedNumber(q.getParameter("bedNumber"));f.setStatus(q.getParameter("status"));return f;}protected void show(HttpServletRequest q,HttpServletResponse r,String m)throws ServletException,IOException{q.setAttribute("formMode",m);q.getRequestDispatcher("/WEB-INF/views/admin/beds/form.jsp").forward(q,r);}}
